-- data_20260525031000_b11_cwd_supersession_audit.sql
-- DR-2026-05-24 Pass 2: CWD retroactive supersession audit (cognitive-wayfinding-design)
-- 22 anchors audited (1 T1 Co-1 + 4 T2 + 9 T3 clinical + 7 T5 national_fw + 1 sr_meta)
-- Distribution: 18 current_best + 3 refined_by + 1 co1_addition_logged.
-- First Co-1 outcome recorded under owner-confirmed accumulation rule (2026-05-25).
-- Key refinements: Tola 2021 + Black 2022 refined_by Zaikina 2025 SR (lighting/color subset).
-- DSDC EADDAT 2022 Co-1 anchor remains operative; co1_addition_logged per accumulation default.

PRAGMA foreign_keys = ON;
BEGIN TRANSACTION;

INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-07c47f68e849', 'cognitive-wayfinding-design', 'CWD-01', 'REF-00202', 3, 'clinical', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "pubmed_search_composite", "query": "dementia wayfinding built environment design SR + dementia friendly design environment quality of life", "date_filter": "published_after:2022", "candidates_returned": 16, "candidates_reviewed": 4}', 16, 4, '2026-05-25T03:13:05Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'pubmed_search', 'Marquardt 2011 wayfinding for people with dementia. Foundational reference. Cluster search returned 16 candidates 2023-2025; none are SR specifically replacing wayfinding evidence. The Siegelaar 2025 meta-review on physical environment + QoL/behavior in dementia (CWD-22 in slug) covers adjacent scope without superseding the specific wayfinding mechanism. Anchor current best.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-9b129475fc28', 'cognitive-wayfinding-design', 'CWD-02', 'REF-00486', 3, 'clinical', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "pubmed_search_composite", "query": "dementia wayfinding built environment design SR + dementia friendly design environment quality of life", "date_filter": "published_after:2022", "candidates_returned": 16, "candidates_reviewed": 4}', 16, 4, '2026-05-25T03:13:05Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'pubmed_search', 'Marquardt 2009 dementia-friendly architecture. Foundational reference; no SR replacement found in 2022-2025 cluster search. The dementia-environment literature has accumulated CWD-22 Siegelaar 2025 meta-review on QoL+behavior but architecture-specific framework not replaced. Anchor current best.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-94a174d8a696', 'cognitive-wayfinding-design', 'CWD-03', 'REF-00487', 3, 'clinical', 'refined_by', '["REF-00488"]', NULL, 'Behavioral patterns refinement: van Buuren 2025 (CWD-04, REF-00488) Front Dementia paper refines the dementia-friendly design framework on wayfinding behavioral patterns dimension. Same-author sequential work; anchor still governs the 2022 framework synthesis; new work narrows to behavioral-pattern observation.', NULL, '{"tool": "pubmed_search_composite", "query": "dementia wayfinding built environment design SR + dementia friendly design environment quality of life", "date_filter": "published_after:2022", "candidates_returned": 16, "candidates_reviewed": 4}', 16, 4, '2026-05-25T03:13:05Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'composite', 'Sequential van Buuren work. CWD-04 is already an anchor in the slug, so the refinement is internal.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-9550d35f4219', 'cognitive-wayfinding-design', 'CWD-04', 'REF-00488', 3, 'clinical', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "pubmed_search_composite", "query": "dementia wayfinding built environment design SR + dementia friendly design environment quality of life", "date_filter": "published_after:2022", "candidates_returned": 16, "candidates_reviewed": 4}', 16, 4, '2026-05-25T03:13:05Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'pubmed_search', 'van Buuren 2025 wayfinding behavioral patterns. Already 2025 anchor; no superseding work found. Current best.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-7aa875e89ea3', 'cognitive-wayfinding-design', 'CWD-05', 'REF-00481', 3, 'clinical', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "pubmed_search_composite", "query": "dementia wayfinding built environment design SR + dementia friendly design environment quality of life", "date_filter": "published_after:2022", "candidates_returned": 16, "candidates_reviewed": 4}', 16, 4, '2026-05-25T03:13:05Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'pubmed_search', 'Wiener 2021 ageing- and dementia-friendly design (PMC8545728). Foundational integration of cognitive psych + neuropsych + environmental psych for design guidelines. Siegelaar 2025 (CWD-22 in slug) covers QoL+behavior meta-review adjacent. Wiener 2021 still governs the disorientation-prevention design-guidelines synthesis. Current best.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-e709834d82ec', 'cognitive-wayfinding-design', 'CWD-06', 'REF-00489', 3, 'clinical', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "pubmed_search_composite", "query": "dementia wayfinding built environment design SR + dementia friendly design environment quality of life", "date_filter": "published_after:2022", "candidates_returned": 16, "candidates_reviewed": 4}', 16, 4, '2026-05-25T03:13:05Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'pubmed_search', 'Marquardt 2014 impact of built environment on dementia. No comprehensive SR replacement found. Current best by absence of superseding SR.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-50769d2fde13', 'cognitive-wayfinding-design', 'CWD-07', 'REF-00710', 2, 'sr_meta', 'refined_by', NULL, '["10.1177/19375867251373096"]', 'Lighting + color sub-dimension SR: Zaikina et al 2025 HERD systematic literature review on indoor lighting + color effects for ASD (7 studies PRISMA). Refines Tola 2021 broader autism BE SR on the specific lighting/color parameters. Anchor still governs the broader BE design framework for autism; new SR refines the lighting + color claim-space with focused evidence quality assessment.', NULL, '{"tool": "pubmed_search", "query": "autism built environment design systematic review", "date_filter": "published_after:2022", "candidates_returned": 3, "candidates_reviewed": 2}', 3, 2, '2026-05-25T03:13:05Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'pubmed_search', 'Zaikina 2025 doi 10.1177/19375867251373096 — focused SR on lighting + color refines Tola 2021 sub-dimension.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-d7a2f29bd6ba', 'cognitive-wayfinding-design', 'CWD-08', 'REF-00048', 3, 'clinical', 'refined_by', NULL, '["10.1177/19375867251373096", "10.1016/j.envpol.2026.127992"]', 'Multi-dimensional refinement: Zaikina 2025 SR refines on lighting/color subset; Al Qutub 2026 IEQ primary study refines on Saudi Arabia jurisdictional + multi-parameter IEQ integration (sound + PM + CO2 + humidity + illuminance). Anchor Black 2022 broader autism+BE considerations still governs; refinements add depth on lighting + color and breadth on non-Western jurisdictional coverage.', NULL, '{"tool": "pubmed_search", "query": "autism built environment design systematic review", "date_filter": "published_after:2022", "candidates_returned": 3, "candidates_reviewed": 2}', 3, 2, '2026-05-25T03:13:05Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'pubmed_search', 'Same Zaikina 2025 + Al Qutub 2026 candidates as CWD-07 and RAP-31. Anchor remains current for the broader synthesis.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-782b7c061150', 'cognitive-wayfinding-design', 'CWD-09', 'REF-00491', 2, 'standard_eb', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "pubmed_search", "query": "autism built environment design systematic review", "date_filter": "published_after:2022", "candidates_returned": 3, "candidates_reviewed": 2}', 3, 2, '2026-05-25T03:13:06Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'pubmed_search', 'Mostafa 2023 ASPECTSS Autism Design Index applied to higher-education. Recent (2 years pre-audit) named index; no replacing autism-design-index work surfaced. Current best for the ASPECTSS framework specifically.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-5111946cc749', 'cognitive-wayfinding-design', 'CWD-10', 'REF-00492', 1, 'co1', 'co1_addition_logged', NULL, NULL, NULL, NULL, '{"tool": "web_search", "query": "Dementia Services Development Centre DSDC 2024 OR 2025 environment design assessment update", "date_filter": "published_after:2022", "candidates_returned": 7, "candidates_reviewed": 5}', 7, 5, '2026-05-25T03:13:42Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'composite', 'DSDC Environments for Ageing and Dementia Design Assessment Tool (EADDAT) 2022. Per owner-confirmed Co-1 supersession treatment (accumulation, not replacement), and per skill section 3 default of co1_addition_logged unless explicit invalidation. EADDAT remains the active DSDC tool through 2024-2025 per Stirling University DSDC blog (no retraction or replacement notice). EADDAT itself replaced the older Dementia Design Audit Tool (DAT) 2008. No further superseding tool announced. The Co-1 corpus accumulates: Bowbrook Care Home Gold Award case studies 2024 and Kirklees Council adoption add to the Co-1 evidence base alongside the named-organization framework rather than replacing it. Anchor remains current as DSDCs operative design framework.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-89cb189ee598', 'cognitive-wayfinding-design', 'CWD-11', 'REF-00493', 3, 'clinical', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "pubmed_search_composite", "query": "dementia friendly design environment quality of life + dementia environmental assessment tools", "date_filter": "published_after:2022", "candidates_returned": 16, "candidates_reviewed": 3}', 16, 3, '2026-05-25T03:13:42Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'pubmed_search', 'Calkins 2022 Evaluation of environmental assessment tools for dementia (Alzheimers & Dementia). Specialized methodological synthesis of assessment tools (DAT, EAT, EHE, EVOLVE, etc). No newer comprehensive synthesis of dementia env-assessment tools found in cluster search. Current best.');
