INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-c60c1a6b8866', 'cognitive-wayfinding-design', 'CWD-14', 'REF-00496', 5, 'national_fw', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "composite", "query": "jurisdiction-specific framework supersession check", "date_filter": "published_after:anchor_year", "candidates_returned": 1, "candidates_reviewed": 1}', 1, 1, '2026-05-25T03:13:42Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'composite', 'Cerema 2022 Construire ou rénover une structure daccueil Alzheimer (French institutional). 3-year-old French jurisdictional framework; no Cerema update identified. Current best subject to French jurisdiction-tracker verification.');
